CREATE EXTERNAL TABLE IF NOT EXISTS users (user_id INT, name STRING, age INT, country STRING, signup_date STRING) ROW FORMAT DELIMITED FIELDS TERMINATED BY ',' STORED AS TEXTFILE LOCATION '/datasets/' TBLPROPERTIES ('skip.header.line.count'='1');

WITH young_users AS (
  SELECT * FROM users WHERE age < 25
)
SELECT country, COUNT(*) FROM young_users GROUP BY country;

CREATE EXTERNAL TABLE IF NOT EXISTS users (user_id INT, name STRING, age INT, country STRING, signup_date STRING) ROW FORMAT DELIMITED FIELDS TERMINATED BY ',' STORED AS TEXTFILE LOCATION '/datasets/' TBLPROPERTIES ('skip.header.line.count'='1');
CREATE EXTERNAL TABLE IF NOT EXISTS orders (order_id INT, user_id INT, product STRING, amount DOUBLE, order_date STRING) ROW FORMAT DELIMITED FIELDS TERMINATED BY ',' STORED AS TEXTFILE LOCATION '/datasets/' TBLPROPERTIES ('skip.header.line.count'='1');

SELECT name FROM users u WHERE EXISTS (
  SELECT 1 FROM orders o WHERE o.user_id = u.user_id
);

CREATE EXTERNAL TABLE IF NOT EXISTS users (user_id INT, name STRING, age INT, country STRING, signup_date STRING) ROW FORMAT DELIMITED FIELDS TERMINATED BY ',' STORED AS TEXTFILE LOCATION '/datasets/' TBLPROPERTIES ('skip.header.line.count'='1');

SELECT name, country, age,
  RANK() OVER (PARTITION BY country ORDER BY age DESC) as age_rank
FROM users;

CREATE EXTERNAL TABLE IF NOT EXISTS users (user_id INT, name STRING, age INT, country STRING, signup_date STRING) ROW FORMAT DELIMITED FIELDS TERMINATED BY ',' STORED AS TEXTFILE LOCATION '/datasets/' TBLPROPERTIES ('skip.header.line.count'='1');

SELECT name, country,
  ROW_NUMBER() OVER (PARTITION BY country ORDER BY name) as row_num
FROM users;

CREATE EXTERNAL TABLE IF NOT EXISTS users (user_id INT, name STRING, age INT, country STRING, signup_date STRING) ROW FORMAT DELIMITED FIELDS TERMINATED BY ',' STORED AS TEXTFILE LOCATION '/datasets/' TBLPROPERTIES ('skip.header.line.count'='1');

SELECT name, country,
  LAG(name, 1) OVER (PARTITION BY country ORDER BY user_id) as prev_user
FROM users;

CREATE EXTERNAL TABLE IF NOT EXISTS users (user_id INT, name STRING, age INT, country STRING, signup_date STRING) ROW FORMAT DELIMITED FIELDS TERMINATED BY ',' STORED AS TEXTFILE LOCATION '/datasets/' TBLPROPERTIES ('skip.header.line.count'='1');

SELECT name, age,
  DENSE_RANK() OVER (ORDER BY age DESC) as dense_rank
FROM users;
